// Vynex Deployer v15.0.0 — embedded Vynex Native panel core, manual updates only.
// This Worker uses only the embedded Vynex core and has no scheduled or automatic source updater.

const APP_NAME = "Vynex Deployer v15.0.0 Native";
const APP_VERSION = "15.0.0";
const PANEL_VERSION = "15.0.0-vynex-native";
const PANEL_MODULE = "vynex-panel.js";
const PANEL_COMPATIBILITY_DATE = "2026-07-01";
const EXPECTED_PANEL_SHA256 = "78db843e6a14c729afa1e8165e9499403e7d8f0742e4374b6212f926cc9aa8ea";
const CF_API = "https://api.cloudflare.com/client/v4";
const DEFAULT_PREFIX = "vynex-panel";
const TOKEN_URL = "https://dash.cloudflare.com/profile/api-tokens?permissionGroupKeys=%5B%7B%22key%22%3A%22workers_scripts%22%2C%22type%22%3A%22edit%22%7D%2C%7B%22key%22%3A%22d1%22%2C%22type%22%3A%22edit%22%7D%2C%7B%22key%22%3A%22account_settings%22%2C%22type%22%3A%22read%22%7D%5D&accountId=%2A&zoneId=all&name=Vynex%20Deployer";
const PANEL_CODE_B64_PARTS = [
``,
``,
``,
``,
``
];

export default {
  async fetch(request) {
    try {
      const url = new URL(request.url);
      if (request.method === "GET" && url.pathname === "/") return html(renderHome());
      if (request.method === "GET" && url.pathname === "/health") return json(await healthPayload());
      if (request.method === "GET" && url.pathname === "/manifest") return json(await healthPayload());
      if (request.method === "GET" && url.pathname === "/frozen-core.js") {
        const code = await getVerifiedPanelCode();
        return new Response(code, { headers: { "Content-Type": "application/javascript; charset=utf-8", "Cache-Control": "no-store" } });
      }
      if (request.method === "POST" && url.pathname === "/deploy") return await handleDeploy(request);
      if (request.method === "GET" && url.pathname === "/updater") return html(renderUpdater());
      if (request.method === "POST" && url.pathname === "/manage") return await handleManage(request);
      return html(renderMessage("مسیر پیدا نشد", "این آدرس در Vynex Deployer وجود ندارد.", false), 404);
    } catch (error) {
      return html(renderMessage("خطای داخلی Deployer", formatError(error), false), 500);
    }
  },
};

async function healthPayload() {
  const code = await getVerifiedPanelCode();
  return {
    ok: true,
    app: APP_NAME,
    version: APP_VERSION,
    panel_version: PANEL_VERSION,
    frozen: true,
    automatic_updates: false,
    source_fetch: false,
    manual_updater: "/updater",
    config_count: 6,
    panel_sha256: await sha256Hex(code),
  };
}

async function handleDeploy(request) {
  let createdDb = null;
  let accountId = "";
  try {
    const form = await request.formData();
    const token = textValue(form, "token");
    const requestedAccountId = textValue(form, "account_id");
    const requestedSubdomain = sanitizeSubdomain(textValue(form, "subdomain"));
    const prefix = sanitizeName(textValue(form, "prefix") || DEFAULT_PREFIX, DEFAULT_PREFIX);
    if (!token) throw new Error("توکن Cloudflare خالی است.");

    const account = await selectAccount(token, requestedAccountId);
    accountId = account.id;
    const subdomain = await ensureWorkersSubdomain(token, accountId, requestedSubdomain);
    const suffix = randomId(7);
    const scriptName = sanitizeName(`${prefix}-${suffix}`, `${DEFAULT_PREFIX}-${suffix}`);
    const dbName = sanitizeResourceName(`${scriptName}-db`, `${DEFAULT_PREFIX}-${suffix}-db`);

    const dbData = await cfJson(`/accounts/${accountId}/d1/database`, token, {
      method: "POST",
      jsonBody: { name: dbName },
    });
    const dbId = dbData?.result?.uuid || dbData?.result?.id;
    if (!dbId) throw new Error("دیتابیس ساخته شد اما شناسه D1 در پاسخ Cloudflare نبود.");
    createdDb = { id: dbId, name: dbName };

    const panelCode = await getVerifiedPanelCode();
    await uploadPanelWorker(token, accountId, scriptName, dbId, panelCode);
    await enableWorkerSubdomain(token, accountId, scriptName);

    const rootUrl = `https://${scriptName}.${subdomain}.workers.dev/`;
    const panelUrl = `${rootUrl}panel`;
    return html(renderDeploySuccess({
      accountName: account.name || account.id,
      accountId,
      scriptName,
      dbName,
      dbId,
      panelUrl,
      rootUrl,
    }));
  } catch (error) {
    return html(renderMessage("ساخت پنل ناموفق بود", formatError(error), false), 400);
  }
}

async function handleManage(request) {
  try {
    const form = await request.formData();
    const token = textValue(form, "token");
    const requestedAccountId = textValue(form, "account_id");
    const prefix = sanitizeName(textValue(form, "prefix") || DEFAULT_PREFIX, DEFAULT_PREFIX);
    const action = textValue(form, "action") || "list";
    const selectedScript = sanitizeName(textValue(form, "script_name"), "");
    if (!token) throw new Error("توکن Cloudflare خالی است.");

    const account = await selectAccount(token, requestedAccountId);
    const panels = await listPanelWorkers(token, account.id, prefix);

    if (action === "list") {
      const enriched = [];
      for (const panel of panels) {
        const db = await resolvePanelDatabase(token, account.id, panel.name).catch(() => null);
        enriched.push({ ...panel, db });
      }
      return html(renderPanelList({ token, account, prefix, panels: enriched }));
    }

    let targets;
    if (action === "update_one") {
      if (!selectedScript) throw new Error("نام پنل برای آپدیت انتخاب نشده است.");
      targets = panels.filter((p) => p.name === selectedScript);
      if (!targets.length) throw new Error("پنل انتخاب‌شده در این اکانت پیدا نشد.");
    } else if (action === "update_all") {
      targets = panels;
      if (!targets.length) throw new Error("هیچ پنل Vynex با این پیشوند پیدا نشد.");
    } else {
      throw new Error("عملیات مدیریت نامعتبر است.");
    }

    const panelCode = await getVerifiedPanelCode();
    const results = [];
    for (const target of targets) {
      try {
        const db = await resolvePanelDatabase(token, account.id, target.name);
        if (!db?.id) throw new Error("Binding دیتابیس DB پیدا نشد؛ برای محافظت از کاربران، آپدیت متوقف شد.");
        await uploadPanelWorker(token, account.id, target.name, db.id, panelCode);
        await enableWorkerSubdomain(token, account.id, target.name);
        results.push({ name: target.name, ok: true, dbId: db.id, note: "هسته Frozen اعمال شد و دیتابیس حفظ شد." });
      } catch (error) {
        results.push({ name: target.name, ok: false, note: formatError(error) });
      }
    }
    return html(renderUpdateResults(account, results));
  } catch (error) {
    return html(renderMessage("مدیریت پنل‌ها ناموفق بود", formatError(error), false), 400);
  }
}

async function getVerifiedPanelCode() {
  const binary = atob(PANEL_CODE_B64_PARTS.join(""));
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  const code = new TextDecoder().decode(bytes);
  const hash = await sha256Hex(code);
  if (hash !== EXPECTED_PANEL_SHA256) throw new Error("هسته Frozen آسیب دیده است؛ SHA-256 مطابقت ندارد.");
  validatePanelCode(code);
  return code;
}

function validatePanelCode(code) {
  const required = [
    'import { connect } from "cloudflare:sockets";',
    "export default",
    "DbService.ensureSchema(env.DB)",
    "UPDATES_ARE_MANAGED_ONLY_BY_VYNEX_DEPLOYER",
    "splitVynexIpPools",
    "Vynex | Irancell Turbo",
    "Vynex | Irancell Backup",
    "Vynex | Irancell Stable",
    "Vynex | Hamrah Turbo",
    "Vynex | Hamrah Backup",
    "Vynex | Hamrah Stable",
    "vynexPortSecurity",
    "X-Vynex-Config-Count",
    "&fragment=",
  ];
  for (const marker of required) {
    if (!code.includes(marker)) throw new Error(`هسته Frozen ناقص است: ${marker}`);
  }
  const forbidden = ["refs/heads/main", ["raw", "githubusercontent", "com"].join("."), "source_url", "external_panel_source"];
  for (const marker of forbidden) {
    if (code.includes(marker)) throw new Error(`وابستگی ممنوع در هسته پیدا شد: ${marker}`);
  }
}

async function sha256Hex(value) {
  const bytes = new TextEncoder().encode(value);
  const digest = await crypto.subtle.digest("SHA-256", bytes);
  return Array.from(new Uint8Array(digest), (b) => b.toString(16).padStart(2, "0")).join("");
}

async function selectAccount(token, requestedAccountId) {
  const data = await cfJson("/accounts", token);
  const accounts = Array.isArray(data.result) ? data.result : [];
  if (!accounts.length) throw new Error("هیچ اکانتی با این توکن پیدا نشد.");
  if (requestedAccountId) {
    const match = accounts.find((a) => a.id === requestedAccountId);
    if (!match) throw new Error("Account ID واردشده در دسترسی این توکن نیست.");
    return match;
  }
  return accounts[0];
}

async function ensureWorkersSubdomain(token, accountId, requested) {
  const current = await cfTry(`/accounts/${accountId}/workers/subdomain`, token);
  const existing = current?.result?.subdomain;
  if (existing) return existing;

  const candidates = [];
  if (requested) candidates.push(requested);
  for (let i = 0; i < 5; i++) candidates.push(`vynex-${randomId(7)}`);
  let lastError = null;
  for (const candidate of candidates) {
    try {
      const created = await cfJson(`/accounts/${accountId}/workers/subdomain`, token, {
        method: "PUT",
        jsonBody: { subdomain: candidate },
      });
      return created?.result?.subdomain || candidate;
    } catch (error) {
      lastError = error;
    }
  }
  throw new Error(`ساخت workers.dev subdomain ناموفق بود: ${formatError(lastError)}`);
}

async function uploadPanelWorker(token, accountId, scriptName, dbId, panelCode) {
  const metadata = {
    main_module: PANEL_MODULE,
    compatibility_date: PANEL_COMPATIBILITY_DATE,
    bindings: [{ type: "d1", name: "DB", id: dbId }],
    observability: {
      enabled: true,
      head_sampling_rate: 1,
      logs: {
        enabled: true,
        invocation_logs: true,
        head_sampling_rate: 1
      }
    },
    annotations: {
      "workers/message": "Vynex Native 15.0.0 manual core update",
      "workers/tag": "vynex-15.0.0-native"
    }
  };
  const form = new FormData();
  form.append("metadata", new Blob([JSON.stringify(metadata)], { type: "application/json" }));
  form.append(PANEL_MODULE, new Blob([panelCode], { type: "application/javascript+module" }), PANEL_MODULE);
  await cfJson(`/accounts/${accountId}/workers/scripts/${encodeURIComponent(scriptName)}`, token, {
    method: "PUT",
    body: form,
  });
}

async function enableWorkerSubdomain(token, accountId, scriptName) {
  await cfJson(`/accounts/${accountId}/workers/scripts/${encodeURIComponent(scriptName)}/subdomain`, token, {
    method: "POST",
    jsonBody: { enabled: true, previews_enabled: true },
  });
}

async function listPanelWorkers(token, accountId, prefix) {
  const data = await cfJson(`/accounts/${accountId}/workers/scripts`, token);
  const rows = Array.isArray(data.result) ? data.result : [];
  return rows
    .map((item) => ({
      name: typeof item === "string" ? item : (item.id || item.name || item.script_name || ""),
      modified: typeof item === "object" && item ? (item.modified_on || item.updated_on || "") : "",
    }))
    .filter((item) => item.name && item.name.startsWith(prefix + "-"))
    .sort((a, b) => a.name.localeCompare(b.name));
}

async function resolvePanelDatabase(token, accountId, scriptName) {
  const endpoints = [
    `/accounts/${accountId}/workers/scripts/${encodeURIComponent(scriptName)}/bindings`,
    `/accounts/${accountId}/workers/scripts/${encodeURIComponent(scriptName)}/settings`,
    `/accounts/${accountId}/workers/scripts/${encodeURIComponent(scriptName)}/script-settings`,
  ];
  for (const endpoint of endpoints) {
    const data = await cfTry(endpoint, token);
    const bindings = Array.isArray(data?.result) ? data.result : (Array.isArray(data?.result?.bindings) ? data.result.bindings : []);
    const found = bindings.find((b) => b && b.type === "d1" && b.name === "DB");
    const id = found && (found.id || found.database_id || found.uuid);
    if (id) return { id, name: found.database_name || "DB", source: "binding" };
  }

  const dbData = await cfJson(`/accounts/${accountId}/d1/database`, token);
  const dbs = Array.isArray(dbData.result) ? dbData.result : [];
  const dash = scriptName.lastIndexOf("-");
  const prefix = dash > 0 ? scriptName.slice(0, dash) : scriptName;
  const suffix = dash > 0 ? scriptName.slice(dash + 1) : "";
  const candidates = new Set([
    `${scriptName}-db`,
    suffix ? `${prefix}-db-${suffix}` : "",
    suffix ? `${prefix}-${suffix}-db` : "",
  ].filter(Boolean));
  const match = dbs.find((db) => candidates.has(db.name));
  if (!match) throw new Error(`دیتابیس متناظر با ${scriptName} پیدا نشد.`);
  return { id: match.uuid || match.id, name: match.name, source: "database-list" };
}

async function cfJson(path, token, options = {}) {
  const headers = new Headers(options.headers || {});
  headers.set("Authorization", `Bearer ${token}`);
  let body = options.body;
  if (options.jsonBody !== undefined) {
    headers.set("Content-Type", "application/json");
    body = JSON.stringify(options.jsonBody);
  }
  const response = await fetch(CF_API + path, {
    method: options.method || "GET",
    headers,
    body,
  });
  const raw = await response.text();
  let data;
  try { data = raw ? JSON.parse(raw) : {}; }
  catch { throw new Error(`پاسخ Cloudflare JSON نبود. HTTP ${response.status}: ${raw.slice(0, 300)}`); }
  if (!response.ok || data.success === false) {
    const details = [...(data.errors || []), ...(data.messages || [])]
      .map((e) => `${e.code ? e.code + ": " : ""}${e.message || JSON.stringify(e)}`)
      .join(" | ");
    throw new Error(details || `Cloudflare API error: HTTP ${response.status}`);
  }
  return data;
}

async function cfTry(path, token) {
  try { return await cfJson(path, token); }
  catch { return null; }
}

function textValue(form, name) {
  return String(form.get(name) || "").trim();
}
function randomId(length) {
  const bytes = new Uint8Array(length);
  crypto.getRandomValues(bytes);
  return Array.from(bytes, (b) => (b % 36).toString(36)).join("");
}
function sanitizeName(value, fallback) {
  const cleaned = String(value || "").toLowerCase().replace(/[^a-z0-9-]+/g, "-").replace(/^-+|-+$/g, "").replace(/-+/g, "-").slice(0, 63);
  return cleaned || fallback;
}
function sanitizeResourceName(value, fallback) {
  return sanitizeName(value, fallback).slice(0, 63);
}
function sanitizeSubdomain(value) {
  return String(value || "").toLowerCase().replace(/[^a-z0-9-]+/g, "-").replace(/^-+|-+$/g, "").replace(/-+/g, "-").slice(0, 32);
}
function formatError(error) {
  if (!error) return "خطای نامشخص";
  return String(error.message || error.stack || error);
}
function escapeHtml(value) {
  return String(value ?? "").replace(/[&<>"']/g, (char) => {
    switch (char) {
      case "&": return "&amp;";
      case "<": return "&lt;";
      case ">": return "&gt;";
      case '"': return "&quot;";
      case "'": return "&#39;";
      default: return char;
    }
  });
}
function escapeAttr(value) { return escapeHtml(value); }
function html(body, status = 200) {
  return new Response(body, { status, headers: { "Content-Type": "text/html; charset=utf-8", "Cache-Control": "no-store, max-age=0", "X-Content-Type-Options": "nosniff" } });
}
function json(value, status = 200) {
  return new Response(JSON.stringify(value, null, 2), { status, headers: { "Content-Type": "application/json; charset=utf-8", "Cache-Control": "no-store" } });
}

function page(title, content) {
  return `<!doctype html><html lang="fa" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${escapeHtml(title)}</title>${styles()}</head><body><div class="glow"></div><main class="wrap">${content}</main></body></html>`;
}
function renderHome() {
  return page(APP_NAME, `<header class="hero"><div class="logo">VX</div><h1>Vynex Cloudflare Deployer</h1><p>هسته کاملاً Vynex Native و Embedded؛ بدون دریافت سورس خارجی و بدون آپدیت خودکار.</p><div class="badges"><span>۶ کانفیگ ثابت با پورت انتخابی</span><span>۳ ایرانسل + ۳ همراه</span><span>Manual Update Only</span></div></header>
  <section class="card"><h2>ساخت پنل جدید</h2><form method="post" action="/deploy">
  <label>توکن Cloudflare</label><input name="token" type="password" autocomplete="off" required placeholder="توکن را Paste کن">
  <label>Account ID — اختیاری</label><input name="account_id" dir="ltr" placeholder="اگر چند اکانت داری وارد کن">
  <label>پیشوند پنل</label><input name="prefix" dir="ltr" value="${DEFAULT_PREFIX}">
  <label>ساب‌دامین workers.dev — فقط برای اکانت تازه</label><input name="subdomain" dir="ltr" placeholder="مثلاً vynexali">
  <button type="submit">ساخت پنل Vynex</button></form>
  <div class="actions"><a href="/updater">مدیریت و آپدیت دستی پنل‌ها</a><a class="token" href="${TOKEN_URL}" target="_blank" rel="noopener noreferrer">باز کردن فرم آماده توکن</a></div>
  <div class="token-help"><b>روش ساخت توکن:</b><ol><li>روی «باز کردن فرم آماده توکن» بزن.</li><li>Cloudflare فرم را با دسترسی‌های لازم آماده می‌کند.</li><li><span dir="ltr">Continue to summary</span> سپس <span dir="ltr">Create Token</span> را بزن.</li><li>توکن نمایش‌داده‌شده را کپی کن و اینجا Paste کن.</li></ol><small>ساخت نهایی توکن فقط با تأیید خودت در داشبورد Cloudflare انجام می‌شود؛ این محدودیت امنیتی Cloudflare است.</small></div></section>
  <section class="note"><b>توکن ذخیره نمی‌شود.</b> فقط هنگام درخواست ساخت یا آپدیت به API رسمی Cloudflare ارسال می‌شود. دسترسی‌های فرم آماده: Workers Scripts (Edit)، D1 (Edit) و Account Settings (Read).</section>`);
}
function renderUpdater() {
  return page("مدیریت پنل‌های Vynex", `<header class="hero small"><div class="logo">UP</div><h1>آپدیت دستی پنل‌ها</h1><p>فقط با توکن و فقط وقتی خودت دکمه را بزنی.</p></header>
  <section class="card"><form method="post" action="/manage">
  <input type="hidden" name="action" value="list">
  <label>توکن Cloudflare</label><input name="token" type="password" autocomplete="off" required>
  <label>Account ID — اختیاری</label><input name="account_id" dir="ltr">
  <label>پیشوند پنل‌ها</label><input name="prefix" dir="ltr" value="${DEFAULT_PREFIX}">
  <button type="submit">نمایش پنل‌ها</button></form><a class="back" href="/">بازگشت به ساخت پنل</a></section>`);
}
function renderPanelList({ token, account, prefix, panels }) {
  const rows = panels.length ? panels.map((panel) => `<tr><td dir="ltr">${escapeHtml(panel.name)}</td><td dir="ltr">${escapeHtml(panel.db?.name || "پیدا نشد")}</td><td>${panel.db ? "آماده" : "نیاز به بررسی"}</td><td><form method="post" action="/manage"><input type="hidden" name="token" value="${escapeAttr(token)}"><input type="hidden" name="account_id" value="${escapeAttr(account.id)}"><input type="hidden" name="prefix" value="${escapeAttr(prefix)}"><input type="hidden" name="script_name" value="${escapeAttr(panel.name)}"><input type="hidden" name="action" value="update_one"><button class="mini" type="submit" ${panel.db ? "" : "disabled"}>آپدیت همین پنل</button></form></td></tr>`).join("") : `<tr><td colspan="4">هیچ پنلی با پیشوند ${escapeHtml(prefix)} پیدا نشد.</td></tr>`;
  return page("پنل‌های Vynex", `<header class="hero small"><h1>پنل‌های ${escapeHtml(account.name || account.id)}</h1><p dir="ltr">${escapeHtml(account.id)}</p></header><section class="card wide"><div class="table"><table><thead><tr><th>Worker</th><th>D1</th><th>وضعیت</th><th>عملیات</th></tr></thead><tbody>${rows}</tbody></table></div>${panels.length ? `<form method="post" action="/manage" onsubmit="return confirm('همه پنل‌ها آپدیت شوند؟ دیتابیس‌ها حفظ می‌شوند.')"><input type="hidden" name="token" value="${escapeAttr(token)}"><input type="hidden" name="account_id" value="${escapeAttr(account.id)}"><input type="hidden" name="prefix" value="${escapeAttr(prefix)}"><input type="hidden" name="action" value="update_all"><button type="submit">آپدیت همه پنل‌ها</button></form>` : ""}<a class="back" href="/updater">بازگشت</a></section>`);
}
function renderDeploySuccess(data) {
  return page("پنل Vynex ساخته شد", `<header class="hero small"><div class="logo ok">✓</div><h1>پنل با موفقیت ساخته شد</h1></header><section class="card"><dl><dt>Worker</dt><dd dir="ltr">${escapeHtml(data.scriptName)}</dd><dt>D1 Database</dt><dd dir="ltr">${escapeHtml(data.dbName)}</dd><dt>Account</dt><dd>${escapeHtml(data.accountName)}</dd></dl><div class="actions"><a class="primary" href="${escapeAttr(data.panelUrl)}" target="_blank" rel="noopener">ورود به پنل</a><a href="${escapeAttr(data.rootUrl)}" target="_blank" rel="noopener">باز کردن Worker</a></div><pre dir="ltr">${escapeHtml(data.panelUrl)}</pre><a class="back" href="/">ساخت پنل دیگر</a></section>`);
}
function renderUpdateResults(account, results) {
  const items = results.map((r) => `<li class="${r.ok ? "success" : "failure"}"><b dir="ltr">${escapeHtml(r.name)}</b><span>${escapeHtml(r.note)}</span></li>`).join("");
  return page("نتیجه آپدیت Vynex", `<header class="hero small"><h1>نتیجه آپدیت دستی</h1><p>${escapeHtml(account.name || account.id)}</p></header><section class="card"><ul class="results">${items}</ul><a class="back" href="/updater">بازگشت به مدیریت</a></section>`);
}
function renderMessage(title, detail, ok) {
  return page(title, `<header class="hero small"><div class="logo ${ok ? "ok" : "error"}">${ok ? "✓" : "!"}</div><h1>${escapeHtml(title)}</h1></header><section class="card"><pre>${escapeHtml(detail)}</pre><a class="back" href="/">بازگشت</a></section>`);
}
function styles() {
  return `<style>:root{color-scheme:dark;--bg:#050712;--card:rgba(15,20,38,.88);--line:rgba(255,255,255,.12);--text:#eef5ff;--muted:#a7b2c8;--red:#ff335f;--cyan:#20d7ff;--purple:#8b5cf6}*{box-sizing:border-box}body{margin:0;min-height:100vh;background:linear-gradient(145deg,#050712,#07152a 55%,#080711);color:var(--text);font-family:Tahoma,Arial,sans-serif}.glow{position:fixed;inset:0;pointer-events:none;background:radial-gradient(circle at 15% 90%,rgba(255,51,95,.23),transparent 30%),radial-gradient(circle at 88% 10%,rgba(32,215,255,.18),transparent 32%)}.wrap{position:relative;width:min(820px,94vw);margin:auto;padding:38px 0}.hero{text-align:center;margin-bottom:22px}.hero.small{margin-bottom:16px}.logo{width:74px;height:74px;border-radius:23px;margin:0 auto 16px;display:grid;place-items:center;font-size:25px;font-weight:900;background:linear-gradient(135deg,var(--red),var(--purple),var(--cyan));box-shadow:0 18px 55px rgba(32,215,255,.2)}.logo.ok{background:linear-gradient(135deg,#16a34a,#20d7ff)}.logo.error{background:linear-gradient(135deg,#b91c1c,#ff335f)}h1{margin:0 0 10px;font-size:clamp(27px,5vw,42px)}h2{margin-top:0}.hero p,.note{color:var(--muted);line-height:1.9}.badges{display:flex;flex-wrap:wrap;justify-content:center;gap:8px}.badges span{font-size:12px;padding:7px 10px;border:1px solid var(--line);border-radius:999px;background:rgba(255,255,255,.05)}.card,.note{background:var(--card);border:1px solid var(--line);border-radius:26px;padding:24px;box-shadow:0 30px 90px rgba(0,0,0,.34);backdrop-filter:blur(16px)}.note{margin-top:14px}.wide{width:min(100%,1000px)}label{display:block;margin:15px 2px 7px;font-weight:700;color:#dbe6f9}input{width:100%;padding:15px;border-radius:15px;border:1px solid var(--line);background:rgba(2,6,18,.7);color:#fff;font-size:15px;outline:none}input:focus{border-color:var(--cyan);box-shadow:0 0 0 4px rgba(32,215,255,.12)}button,.actions a,.back{border:0;border-radius:15px;padding:14px 16px;text-decoration:none;color:#fff;font-weight:900;display:flex;justify-content:center;align-items:center;cursor:pointer}button{width:100%;margin-top:20px;font-size:16px;background:linear-gradient(90deg,var(--red),var(--purple),var(--cyan))}button:disabled{opacity:.4;cursor:not-allowed}.mini{margin:0;padding:10px 12px;font-size:12px}.actions{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:14px}.actions a{background:rgba(255,255,255,.07);border:1px solid var(--line)}.actions .primary{background:linear-gradient(90deg,#16a34a,#20d7ff)}.actions .token{background:linear-gradient(90deg,#f97316,#ff335f)}.token-help{margin-top:14px;padding:15px;border-radius:15px;border:1px solid rgba(32,215,255,.25);background:rgba(32,215,255,.07);color:#dbe6f9;line-height:1.9}.token-help ol{margin:8px 0;padding-right:22px}.token-help small{color:var(--muted)}.back{margin-top:14px;background:rgba(255,255,255,.06);border:1px solid var(--line)}pre{white-space:pre-wrap;overflow:auto;background:rgba(0,0,0,.25);border:1px solid var(--line);border-radius:15px;padding:15px;color:#d9e6fa}dl{display:grid;grid-template-columns:150px 1fr;gap:10px}dt{color:var(--muted)}dd{margin:0}.table{overflow:auto}table{width:100%;border-collapse:collapse}th,td{padding:12px;border-bottom:1px solid var(--line);text-align:right;white-space:nowrap}.results{list-style:none;padding:0;margin:0;display:grid;gap:10px}.results li{display:grid;gap:6px;padding:14px;border-radius:15px;border:1px solid var(--line)}.results .success{background:rgba(34,197,94,.09);border-color:rgba(34,197,94,.35)}.results .failure{background:rgba(255,51,95,.09);border-color:rgba(255,51,95,.35)}.results span{color:var(--muted)}@media(max-width:600px){.wrap{padding:20px 0}.card{padding:18px}.actions{grid-template-columns:1fr}dl{grid-template-columns:1fr}dd{margin-bottom:8px}}</style>`;
}
